<template>
  <div class="header">
    <div class="header-inner">
      <div class="logo">
        <img src="../assets/lablogo.png" alt="TVDS Logo" class="logo-img" />
        <div class="logo-copy">
          <span class="logo-title">TVDS Lab</span>
          <span class="logo-subtitle">Time-Varying Data Science</span>
        </div>
      </div>

      <a-menu
        v-model="current"
        mode="horizontal"
        class="main-menu"
        @click="pushmenu"
      >
        <a-menu-item key="index">
          <a-icon type="home" />Home
        </a-menu-item>
        <a-menu-item key="publications">
          <a-icon type="profile" />Publications
        </a-menu-item>
        <a-menu-item key="team">
          <a-icon type="team" />Team
        </a-menu-item>
        <a-menu-item key="award">
          <a-icon type="trophy" />Awards
        </a-menu-item>
        <a-menu-item key="activities">
          <a-icon type="schedule" />Activities
        </a-menu-item>
      </a-menu>
    </div>
  </div>
</template>

<script>
export default {
  data() {
    return {
      current: [this.getMenuKey(this.$route.path)],
    };
  },
  watch: {
    $route(to) {
      this.current = [this.getMenuKey(to.path)];
    },
  },
  methods: {
    getMenuKey(path) {
      const key = path.replace("/", "");
      return key || "index";
    },
    pushmenu(item) {
      if (this.$route.path !== "/" + item.key) {
        this.$router.push({ path: "/" + item.key });
      }
    },
  },
};
</script>

